SELECT c.name, COUNT(l.loan_id) AS loan_count
FROM customers c
JOIN loans l ON c.customer_id = l.customer_id
GROUP BY c.customer_id, c.name
HAVING COUNT(l.loan_id) > (
    SELECT AVG(cnt) FROM (
        SELECT COUNT(*) AS cnt FROM loans GROUP BY customer_id
    )
);

SELECT t.account_id, t.txn_id, t.amount, t.txn_type, t.txn_date
FROM transactions t
WHERE t.txn_date = (
    SELECT MAX(t2.txn_date) FROM transactions t2 WHERE t2.account_id = t.account_id
);
